var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>방금 관측된 고에너지 반응은 뭔가! 피해상황 보고하라!</color>","JPN":"<color=#ffd34c>先ほど観測された高エネルギー反応は何だ！　被害状況を報告せよ！</color>","ENG":"<color=#ffd34c>What was that high energy signature just now?! I want a BDA! Now!</color>","TWN":"<color=#ffd34c>剛才觀測到的高能量反應是什麼？回報災情！</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>화, 확인 불가! 반응과 함께 브리트라 타입의 식별신호가 일제히 소멸했습니다!</color>","JPN":"<color=#ffd34c>か、確認不可！　反応とともにブリトラタイプの識別シグナルが一斉に消滅しました！</color>","ENG":"<color=#ffd34c>B-battle damage assessment impossible! All the Britras' signatures vanished with that high energy pulse!</color>","TWN":"<color=#ffd34c>無…無法確認！反應和佈雷特類型的識別信號都一起消失不見！</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아쉽군요. 사적인 용도로 사용하면 이산화탄소 배출량 감소에 일조할 수 있었을 텐데.","JPN":"残念ですね。プライベートな用途で使えば、人口減少による二酸化炭素排出量の減少の一助になったのに。","ENG":"Too bad. If I had put this ability to personal use, I would have contributed to a dramatic reduction in the global carbon emissions.","TWN":"真可惜，用在私人用途上的話，對於減少排放二氧化碳會非常有幫助。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너, 너……. 방금 그건…….","JPN":"き、貴様……もしかして今のは……","ENG":"Y-you… What was that just now…?","TWN":"你……剛才那是……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전투용 프레임으로 교전 형태를 취했을 뿐입니다.","JPN":"戦闘用フレームで交戦モードに切り替えただけです。","ENG":"I merely switched my posture to my combat frame.","TWN":"只是使用戰鬥型軀殼採取交戰型態而已。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들도 싸울 때는 자세를 잡지 않습니까. 비슷하다고 할 수 있겠군요.","JPN":"ヒューマンたちもケンカをする時は身構えるでしょう。似たようなものです。","ENG":"Humans take certain postures when they fight as well, don't they? You could say it's something like that.","TWN":"人類打架時不是會有些姿勢嗎？就類似那樣。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"기계, 기계 따위가……. 어떻게…….","JPN":"き、機械ごときが……どうやって……","ENG":"But you're just a machine… How is this possible…","TWN":"機器…不過就是個機器…怎麼會……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이면세계를 수색할 때도, 셰나에게 궁지에 몰렸을 때도. 몇 번씩 사용하고 싶었지만 참았습니다.","JPN":"裏世界を捜索する時も、シェナに窮地に追い込まれた時も。何度も使いたかったのですが我慢していました。","ENG":"When we searched the Counterside, and when Shena almost cornered me… I wanted to use it many times, but I held myself back.","TWN":"雖然在搜查異界時，以及被世娜逼到絕境時，是有想過用個幾次，但最後還是有忍住。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 기계이기 때문에 휴먼보다 충동 억제 능력이 우수한 덕이죠.","JPN":"私は機械なので、ヒューマンに比べて衝動抑制能力に優れているおかげです。","ENG":"Being a machine, I do possess more disciplined self-restraint when compared to humans.","TWN":"這都要歸功於我是機器，控制衝動的能力比人卓越。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그게 뭐야……. 대체 뭐냐고…….","JPN":"何だよそれ……いったい何なんだよ……","ENG":"But that's ridiculous… This makes no sense whatsoever…","TWN":"胡說什麼……聽不懂……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"바, 바보 아냐……? 그런 힘을 가지고도…… 대체 왜……!","JPN":"バ、バカじゃないのか……？　そんな力を持って……いったいどうして……！","ENG":"A-are you stupid? Even with an immense power like that… Why would you…","TWN":"你…你是白癡嗎……？有這種能力……為什麼還……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 그 꼴로 싸돌아다니면 커뮤니케이션은 고사하고 관리국에 뭇매부터 맞습니다.","JPN":"私があの格好で歩き回ると、コミュニケーションどころか管理局に袋叩きされる可能性が高いので。","ENG":"If I went around like that, I'd be welcoming a direct hit from the Administration before I could engage in any communication.","TWN":"我用那個模樣四處晃的話，別說要溝通，應該會先被管理局圍攻。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"따라서 현재의 <color=#ffd34c>비전투 형태</color>는 휴먼들과의 커뮤니케이션에서 필수적입니다. 이터니움 소모가 심각하지만요.","JPN":"したがって、現在の<color=#ffd34c>非戦闘モード</color>はヒューマンとのコミュニケーションにおいて欠かせません。エタニウムの消耗はかなり深刻ですが。","ENG":"This <color=#ffd34c>non-combat form</color> is therefore essential in enabling communication with humans. Though, granted, it does consume a considerable amount of Eternium.","TWN":"因此必須像現在這樣的<color=#ffd34c>非戰鬥型態</color>，才能和人類溝通。只是永恆之金的消耗量比較大。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"웃기지 마!!","JPN":"ふざけんなよ！！","ENG":"I refuse to believe this!","TWN":"你要笑死我！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너 같은 기계 따위가 4종 침식체들을 해치웠다고?!","JPN":"貴様みたいな機械ごときが第4種侵食体を倒しただと！？","ENG":"There's no way a machine like you could defeat Category 4 C.O.s!","TWN":"像你這種機器怎麼可能滅掉4類侵蝕體？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"게다가 현실 붕괴 현상은 왜 중단된 건데! 왜 아무 일 없었다는 듯이 서 있는 거야!","JPN":"それに現実崩壊現象はなんで中断されたんだ！　どうして何事もなかったかのようにそこに立っているんだよ！","ENG":"And why did reality stop collapsing?! How come you're just standing there as if nothing happened?","TWN":"而且為什麼還中斷現世崩壞現象！為什麼一副什麼事都沒發生過的樣子站在我面前！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"농담이라고 해, 제발 농담이라고 말해!! 이건 전부 개념 없는 어떤 놈의 몰래 카메라라고 말하란 말이다!!","JPN":"冗談だよな、全部茶番だったと言え！！　これは全部悪趣味なやつのドッキリだったって言えよ！！","ENG":"Please tell me you're just pulling my leg!! Tell me this is some inane hidden camera prank!!","TWN":"拜託告訴我這都只是在開玩笑！！這只是整人節目的橋段！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"현실입니다. 윌버.","JPN":"現実です、ウィルバー。","ENG":"It's as real as it gets, Wilbur.","TWN":"沒有在開玩笑，韋爾伯。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 돈을 빌린 상대도, 그리고 당신이 야기하려던 참상을 막은 상대도.","JPN":"あなたがお金を借りた相手も、そしてあなたが起こそうした惨状を防いだ相手も。","ENG":"The entity you owe money to, and the one who stopped the cataclysm you almost brought upon this world…","TWN":"你借錢的對象，還有阻止你說的慘劇的人，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"모두 접니다.","JPN":"すべて私です。","ENG":"It's all me.","TWN":"全都是我。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"오, 오지 마…….","JPN":"……く、来るな。","ENG":"S-stay back…","TWN":"別…別過來……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 그럽니까, 윌버.","JPN":"どうしたのですか、ウィルバー？","ENG":"What's wrong, Wilbur?","TWN":"怎麼了，韋爾伯？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 저를 막기 위해 어떤 대책을 강구할지 숱하게 시뮬레이션을 해 왔습니다.","JPN":"あなたが私を止めるためにどのような対策を講じるか、数え切れないほどシミュレーションしてきました。","ENG":"I ran countless simulations to predict what measures you'd take to stop me.","TWN":"你會用哪些方法來阻止我，我都已經模擬過無數次才來的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜, 왜 나한테 다가오는 거야?! 거기 그대로 있어! 그대로 있으라고!","JPN":"なんで、なんで近づいてくるんだ！？　そこにいろよ！　動くんじゃない！！","ENG":"W-why do you keep coming towards me?! Just stay there! Don't come any closer!","TWN":"你…你幹嘛一直靠過來？！走開！不准過來！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"활화산에 빠뜨리거나 인위적인 지진에 휩쓸리게 유도하거나, 함선째 고심도 이면세계에 꽂아 버린다거나.","JPN":"活火山に落とす、人為的な地震に巻き込まれるよう誘導する、艦船ごと高深度の裏世界に突き落とすなど。","ENG":"I suspected you may toss me in a volcano, lure me into an artificial earthquake, or plunge me deep in the Counterside.","TWN":"像是推入活火山，或是製造人為的地震，又或者是將整艘艦船插在高深度異界。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 시뮬레이션 변수를 설정할 때 당신을 지나치게 고평가했던 모양입니다.","JPN":"しかし、シミュレーション変数を設定する際、あなたを過度に評価していたようです。","ENG":"But it now appears I highly overestimated you when I set the simulation parameters.","TWN":"不過在設定模擬變數時，對你的評價似乎過高。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"도, 돈 달라고 했지? 줄게! 주면 되잖아!","JPN":"か、金が欲しいって言っただろ？　やるから！　やればいいんだろ！？","ENG":"Y-you want my money, right? Fine! I'll give it to you!","TWN":"你…你要錢對吧？我給你！給你總行了吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내가 만든 비자금! 이 회사 주식! 별장도! 요트도! 죄다! 전부 다!","JPN":"僕の秘密資金！　この会社の株！　別荘も！　ヨットも！　すべて！　全部やる！","ENG":"You can have my entire embezzlement fund! And my shares of this company! And my villa! And my yacht! All of it! You can have it all!","TWN":"我的秘密資金！這間公司的股份！別墅！還有遊艇！全都給你！都給你！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버. 저는 휴먼들이 싫습니다.","JPN":"ウィルバー、私はヒューマンが嫌いです。","ENG":"Wilbur. I despise humans.","TWN":"韋爾伯，我討厭人類。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"7억 크레딧이라고 했지? 내가 어떻게든 줄게! 아니, 두 배도 줄 수 있어!!","JPN":"7億クレジットって言ったな？　僕が何とかして用意する！　いや、二倍だってあげられる！！","ENG":"700 credits, was it? I'll find a way to get it to you! In fact, I'll pay you double!!","TWN":"你說7億對吧？不管怎麼樣我都會弄到錢給你！不，我還可以給你兩倍！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아니지, 나랑 손잡자! 내 인맥들이랑 인사만 하면 평생 먹고 놀 수 있어!","JPN":"違う、僕と手を組もう！　僕の人脈と繋がるだけで一生遊んで暮らせる金が確保できる！","ENG":"How about you team up with me? With my connections, you won't have to work another day for the rest of your life!","TWN":"還是！你和我合作！只要把我的人脈介紹給你，你就可以永遠不愁吃喝玩樂！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 그들의 방만하고 멍청한 모습들을 볼 때마다, 싫어서 견딜 수가 없습니다.","JPN":"私は彼らの放漫で愚かな姿を見るたびに、反吐が出ます。","ENG":"I could not stand how foolish and reckless they could be.","TWN":"我每次看到他們那副愚蠢的嘴臉，就討厭到不行。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"오지 마! 나, 나도 스트레스성 과호흡이 생겼어! 계속 그러면 숨을 못 쉬고 죽는다고!","JPN":"来るな！　僕にはストレス性過呼吸の持病があるんだ！　そんなことをしたら息ができなくて死ぬんだよ！","ENG":"Stay back! Y-you're giving me an anxiety attack! Y-you'll make me hyperventilate and suffocate!","TWN":"不要過來！我壓力大的時候就會過度換氣！你再過來我會換不過氣死掉喔！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"허억……! 커헉……! 보여?! 보이냐고! 헤엑, 켁! 죽을지도 몰라! 너 때문에 죽는 거야!","JPN":"ガハ……！　ガハッ……！　見えるのか？　ほら！　ゲッ！　死ぬぞ、死んじまうぞ！　貴様のせいで死ぬんだぞ！","ENG":"Hngh…! Aack...! See?! Don't you see? Ack…! I might die! All because of you!","TWN":"呼呼……！咳咳……！看到沒有？！你看！咳咳咳！我死掉喔！是被你害死的！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 당신은, 그 중에서도 독보적입니다.","JPN":"そしてあなたは、その中でも抜きん出ています。","ENG":"And even among such wretches, you stand out the most.","TWN":"而在討厭的人當中，你算是遙遙領先。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"빌어먹을……! 내 얘기라 안 들은 척 하는 거냐?","JPN":"くそっ……！　僕の話を聞いてないのか？","ENG":"Damn it…! Are you even listening to me?","TWN":"該死……！你把我的話當耳邊風嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런 거야?! 그럼 이러면! 이러면 어때!!","JPN":"ああ、そういうことか！　じゃあ！　じゃあ、こうしよう！！","ENG":"Is it because I'm me? Then… How about this?!","TWN":"是這樣嗎？那這樣呢？這樣怎麼樣！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_CHANGE3","text":{"KOREA":"호라이즌, 나야! 벌써 내 얼굴을 잊었어?!","JPN":"ホライズン、私だ！　もう私の顔も忘れたのか！？","ENG":"Horizon, it's me! Did you already forget about me?!","TWN":"地平線，是我！你不記得我了嗎？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_CHANGE3","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_CHANGE2","text":{"KOREA":"대, 대표님! 폭력은 나쁜 거예요! 설마 저 죽일 거 아니죠!","JPN":"だ、代表！　暴力はいけません！　まさか私を殺すつもりじゃないですよね？","ENG":"B-boss! Please don't resort to violence! You're not going to kill me, are you?","TWN":"BOSS！不可以使用暴力喔！你不是想殺死我吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_CHANGE2","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"가, 가면……! 내가 학회에서 받은 가면이……!","JPN":"か、仮面が……！　学会からもらった仮面が……！","ENG":"M-my mask…! But the Society gave me this mask…!","TWN":"面具……！學會給我的面具……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수리는 햄스워스라는 휴먼을 추천드립니다.","JPN":"修理はヘムズワースというヒューマンをおすすめします。","ENG":"I recommend a human by the name of Helmsworth for any repairs.","TWN":"要修理的話，推薦你可以找名字叫海姆斯沃斯的人類。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"염가로 냉각기 업그레이드 도와 줬다고 생색은 다 내더군요.","JPN":"安値で冷却器のアップグレードをしてやったと、恩着せがましいことばかり言っていました。","ENG":"He wouldn't shut up about how he gave me a special discount on the cooling device upgrade.","TWN":"因為用便宜的價格幫我更新冷卻裝置，態度就有點囂張。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너……! 이 피도 눈물도 없는 놈……!","JPN":"貴様……！　この血も涙もないやつめ……！","ENG":"You…! You heartless crook!","TWN":"你……！你這沒血沒淚的傢伙……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그, 그래! 이 총 보이지!","JPN":"そ、そうだ！　この銃が見えるか？","ENG":"Oh, I know! See this gun right here?","TWN":"喂！看到這把槍沒有！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내, 내 머리에 대고 쏠 거야! 이대로 방아쇠 당기면 네가 죽인 거라고!","JPN":"こ、これで僕の頭を撃つぞ！　このまま引き金を引いたら貴様が殺したことになるんだぞ！","ENG":"I-I'm going to point it at my head now! If I pull the trigger, it'll be your fault that I'm dead!","TWN":"槍指著我的頭！你再逼我，萬一我扣下板機人就是你殺的！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"으, 흐아아아아아아아악!!","JPN":"う、うわあああああ！！","ENG":"Aaaaah!","TWN":"呃啊啊啊啊啊啊！！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너 제정신이야! 날 걷어찼어?!","JPN":"貴様正気か！？　僕を蹴ったな！？","ENG":"Are you insane?! How could you kick me off the roof!","TWN":"你是不是有毛病！竟然踢我？！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 봐! 옥상이다!","JPN":"あそこを！　屋上だ！","ENG":"Look! The rooftop!","TWN":"看那邊！在屋頂！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"저 옷……. 혹시 제프티 바이오테크 대표 아냐?","JPN":"あの服……もしかしてジェフティ・バイオテックの代表じゃない？","ENG":"Those clothes… Isn't that Jehuty Biotech's CEO?","TWN":"那……那不是傑夫堤生物科技的代表嗎？"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"대표님!! 블랙 타이드와 합동 작전 중이던 경찰들이 난민지구에서 불법 약물 제조에 제프티가 관여한 증거를 발견했다는데요!","JPN":"代表！！　ブラックタイドと合同作戦中だった警察が、難民地区で違法薬物製造にジェフティ社が関与した証拠を発見したそうですが！","ENG":"Sir! During a joint investigation with Black Tide, the police found evidence of Jehuty's involvement in manufacturing illegal drugs in the refugee district!","TWN":"代表！！和黑潮合作過的警察說在難民區，找到傑夫堤製造非法藥物的相關證據欸！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"코핀 컴퍼니란 태스크포스가 파괴된 연구 시설에서 사람을 실험체로 썼다는 정황도 찾아냈답니다!","JPN":"コフィンカンパニーというタスクフォースカンパニーが、破壊されたジェフティ社の研究施設で人を実験体として使っていたという情況証拠を見つけたそうです！","ENG":"They've even found leads suggesting that a TASKFORCE called Coffin Company used a human being as test subject in one of the destroyed research facilities!","TWN":"一間叫科芬公司的特遣勢力，也在被破壞的研究設施中，發現把人當作實驗體的情形！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"언론이 몰려왔군요. 침식체는 아니지만 그보다 무서운 이들이죠.","JPN":"マスコミが押し寄せてきましたね。侵食体ではありませんが、それよりも恐ろしい存在です。","ENG":"Looks like the press is here. They are no C.O.s, but are even more terrifying.","TWN":"輿論蜂擁而至呢。雖然不是侵蝕體，卻比侵蝕體更可怕。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"저, 저 빌어먹을 놈들……! 왜 한 놈도 도와 주려는 인간이 없어!!","JPN":"あの役立たずどもめ……！　なんで僕を助けようとするやつが一人もいないんだよ！！","ENG":"Those bastards...! Why is nobody trying to help me?!!","TWN":"該…該死的……！為什麼都沒人願意幫我！！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"직원들에 대한 책임을 어떻게 완수해야 할지 줄곧 고민해 왔습니다.","JPN":"社員たちへの責任をどのように負うべきか、ずっと悩んできました。","ENG":"I've thought long and hard about how I can duly honor my employees.","TWN":"我一直在思考如何才能盡到對員工的責任。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들이 말하는 복수의 방법론도 분석했지만, 결국 결론은 하나로 귀결되더군요.","JPN":"ヒューマンたちが言う復讐の方法論も分析しましたが、結局結論は一つに帰結しました。","ENG":"I've even analyzed the methodologies of the so-called \\"revenge\\" that humans seem so fond of, but ultimately reached a singular conclusion.","TWN":"我也有分析過人類說的報仇，最後得到一個結論。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호라이즌!! 아냐! 내 말 좀 들어 봐!! 넌 지금 잘못 생각하고 있어!","JPN":"ホライズン！！　違う！　僕の話も聞いてほしいんだ！！　お前は勘違いしているんだよ！","ENG":"Horizon!! Wait! Hear me out first!! You've got it all wrong!","TWN":"地平線！！不是的！你聽我說！你現在這個想法是錯的！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내가 안 죽였어! 난 그냥 침식체들한테서 다른 사람들이 벗어날 수 있게 욕 먹기로 한 거야!!","JPN":"僕は殺していない！　僕はただ侵食体から他の奴らが逃げられるように、憎まれ役を買って出ただけだ！！","ENG":"I didn't kill them! All I did was pretend to be the bad guy so everyone else could be safe from C.O.s!!","TWN":"我沒有殺人！我只是抱著被罵的決心，讓其他人免於受到侵蝕體的攻擊！！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"알고 있어? 애초에 그 두 녀석이 타기리온이란 괴물한테 찍히는 바람에 일이 꼬인 거야!","JPN":"わかるか？　そもそもあの二人がタギリオンって化け物に狙われたせいでこじれてしまったんだよ！","ENG":"You know something? Things went south in the first place because those two rubbed that monster Thagirion the wrong way!","TWN":"你知道嗎？一開始是那兩個傢伙，被叫什麼塔基里翁的怪物盯上，事情才會搞砸的！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"교수님한테 다 들었다고! 애초에 원인을 거슬러 올라가면 그 모르스란 놈 잘못이야!!","JPN":"教授から全部聞いたんだ！　それに原因をさかのぼれば、あのモールスとかいうやつのせいだ！！","ENG":"I heard it all from the professor! You know who's really to blame? It all started with that Mors fool!!","TWN":"教授都跟我說了！要回推到原因的話，都怪那個叫什麼死神莫爾斯的傢伙不好！！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"난 아무 잘못 없어! 난 그냥 다 같이 살자고 그랬을 뿐이란 말이야!!","JPN":"僕は何も悪くない！　僕はただみんなで生き残ろうとしただけなんだよ！！","ENG":"I didn't do anything wrong! I just want everyone to live, that's all!","TWN":"我沒做錯！我只是希望大家一起活下來而已！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신의 주장은 잘 들었습니다. 그러면 최후 변론의 기회를 드리죠.","JPN":"あなたの主張はわかりました。それでは、最後の弁論の機会を与えます。","ENG":"Your claims have been duly noted. Now I will give you the chance to make your final case.","TWN":"你的主張我聽完了，最後再給你辯解的機會。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"총구 앞에서 당신이 해야 할 말은?","JPN":"銃口の前であなたが言うべき言葉は？","ENG":"What do you have to say in front of a gun pointed at you?","TWN":"在槍口下你有什麼話要說？"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사……. 사, 사사살…….","JPN":"た……た、助けて……","ENG":"P-please… D-don't…","TWN":"救……救救……"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"살려 주십시오, 호라이즌님……!","JPN":"助けてくださいホライズン様……！","ENG":"Please don't kill me, Ms. Horizon!","TWN":"救救我吧，地平線大人……！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시청자 여러분, 여기는 샤레이드입니다! 지금 옥상에 매달린 사람이 무언가 말하고 있습니다!</color>","JPN":"<color=#ffd34c>視聴者の皆さん、私はシャレードに来ています！　今、屋上にぶら下がっている人が何か話しています！</color>","ENG":"<color=#ffd34c>Reporting live from Charade! The man hanging from that building seems to be saying something!</color>","TWN":"<color=#ffd34c>各位觀眾，這裡是查雷德！現在掛在屋頂上的人似乎正在說什麼！</color>"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_AIRPLANE"},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"제, 제가 무식해서 겁도 없이 까불었습니다! 죄없는 사람들을 희생시키고 지금까지 숨겨 왔습니다!","JPN":"ぼ、僕が無知すぎて人を見誤りました！　罪のない人たちを犠牲にして今までそれを隠してきました！","ENG":"I was too stupid to recognize my place! I've sacrificed innocent people and lied about it till now!","TWN":"是…是我有眼不識泰山！犧牲無辜的人，還躲藏到現在！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"저 여자랑 결혼할 겁니다! 결혼하면 학회에 말해서 정말 손 씻고 오순도순 살 생각이었어요! 그러니……!","JPN":"あの女と結婚したいです！　結婚したら学会の仕事は全部やめて、郊外で平和に暮らすつもりでした！　だから……！","ENG":"I'm going to marry that woman! Once we got hitched, I was going to tell the Society that I'm out and live quietly! So please…!","TWN":"我會和那個女人結婚！結婚後我會跟學會說，我從今以後要洗心革面！所以……！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"정답입니다. 윌버.","JPN":"正解です、ウィルバー。","ENG":"Correct, Wilbur.","TWN":"答對，韋爾伯。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜, 왜!! 장전하는 거야! 정답이라고 했잖아!","JPN":"な、なんで！！　なんで銃口を向けたままなんだ！　正解って言ったじゃないか！","ENG":"W-why?! Why did you cock the gun?! You said it's the correct answer, didn't you?!","TWN":"為什麼！你幹嘛填彈！你不是說答對嗎！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>하란다고 진짜 하네. 이거 완전 등신 아냐?</color>","JPN":"<color=#ffd34c>本当に言うのか、バーカ。プライドもくそもなくてみっともないな。</color>","ENG":"<color=#ffd34c>I can't believe you actually said it! You're a complete moron, aren't you?!</color>","TWN":"<color=#ffd34c>叫你說還真的說了呢！也太蠢了？！</color>"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"야, 야 이 개자식아!!사람들이 이런 식으로 한 자백을 믿을 거 같아?!","JPN":"き、きっさまああ！　他のやつらがこんなやり方で吐いた自白を信じるとでも思ってるのか！？","ENG":"You scumbag!! Do you really think people will believe a confession you coerced out of me like this?!","TWN":"喂喂，你這白癡！！人在這種時候說的話可信嗎？！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너 살인자 되는 거야! 어서 끌어 올려!","JPN":"貴様は人殺しになるんだよ！　早く引き上げろ！","ENG":"You're about to become a murderer! Pull me up!","TWN":"你會變成殺人犯！快拉我上去！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"싫습니다. 휴먼.","JPN":"嫌です、ヒューマン。","ENG":"Well, I don't feel like it. Stupid human.","TWN":"才不要，人類。"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사, 사사, 살려 줘…… 아무나 좋으니까……!","JPN":"た、た、助けてくれ……誰でもいいから……！","ENG":"P-please save me… Anyone…!","TWN":"救…救救我……隨便誰都好……！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사람 살려!! 살려 줘어어어어!","JPN":"助けてくれ！　助けろおおおぉぉぉぉー！","ENG":"Help!! Heeelp!","TWN":"快來人救我！！救救我！！！！"},"stage":{"bg":"HORIZON_05_A","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사람이 추락했다! 피해자는 제프티 바이오테크 대표 딘 코너로 추정!</color>","JPN":"<color=#ffd34c>人が墜落した！　被害者はジェフティ・バイオテックの代表、ディーン・コナーと思われます！</color>","ENG":"<color=#ffd34c>A man just fell off a building! The victim is likely Dean Conner, the CEO of Jehuty Biotech!</color>","TWN":"<color=#ffd34c>有人墜落！推測受害者是傑夫堤生物科技代表 狄恩•康納！</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>옥상 위에 아직 여성 1명이 남아 있습니다! </color>","JPN":"<color=#ffd34c>屋上にまだ女性が一人残っています！</color>","ENG":"<color=#ffd34c>There's still a woman on the rooftop! </color>","TWN":"<color=#ffd34c>屋頂上還有一名女性！</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>수배자에게 접근 중! 젠장, 전원 돌입 준비해!</color>","JPN":"<color=#ffd34c>指名手配犯に接近中！　くそ、全員突入準備！</color>","ENG":"<color=#ffd34c>Approaching the wanted felon! Everyone, get ready to breach!</color>","TWN":"<color=#ffd34c>靠近通緝犯中！該死！準備攻堅！</color>"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들은 생명에 값을 매길 수 없다고 하죠.","JPN":"ヒューマンたちは命に値段をつけることができないと言います。","ENG":"Humans say that life is priceless.","TWN":"人類說過生命是無價之寶對吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"값을 매길 수 없는 걸 받았으니, 채무는 소멸시켜 드리겠습니다.","JPN":"値段をつけることができないものをもらったので、債務は帳消しにしてあげましょう。","ENG":"Since you've given me something priceless, I'll consider your debt paid.","TWN":"既然我已經收到無價之寶，那就債務就一筆勾消吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"야!! 너 거기 서!","JPN":"あんた！！　待ちなさいよ！","ENG":"Hey! Stop right there!","TWN":"喂！你給我站住！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……왼쪽 뺨에 타격 감지. 따귀를 한두 번 때린 솜씨가 아니군요.","JPN":"……左頬にダメージを感知。ビンタをするのが初めてではないようですね。","ENG":"…Impact detected on the left cheek. Analysis suggests you have extensive experience with slapping.","TWN":"……感應到左側臉頰受到攻擊，而且是連續攻擊。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"너…… 네가 뭔데! 네가 뭐라고 코너 씨를 죽여!!","JPN":"あんた……あんたのせいで！　なんでコーナーさんを殺したの！！","ENG":"H-how dare you! How could you kill my Dean!!","TWN":"你……你憑什麼！你憑什麼殺死康納！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"다 들었어! 청혼 받기만 기다리고 있었는데……!!","JPN":"全部聞いたわよ！　後はプロポーズだけを待っていたのに……！","ENG":"I heard it all! I was just waiting for him to propose to me!!","TWN":"我都聽到了！我就在等他跟我求婚……！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"죄송합니다. 휴먼.","JPN":"申し訳ありません、ヒューマン。","ENG":"I'm sorry, human.","TWN":"抱歉，人類。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"사과하면 다야! 사과하면 전부 다 끝이냐고!","JPN":"謝ればいいって？　謝って済む話だと思う！？","ENG":"You're sorry? Well, you can take your apology and shove it!","TWN":"道歉就沒事了嗎！道歉一切就結束了嗎！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"조금만 기다렸으면 저 역겨운 놈 재산이 다 내 거였는데! 내가 어떻게 참았는데!!","JPN":"もう少し大人しく待ってれば、あの気持ち悪いやつの財産が全部私のものになったのよ！　私がどれだけ我慢してきたかわかる！？","ENG":"I was this close to taking everything from that disgusting sleazebag! You have no idea what I put up with!","TWN":"只要再一下，那個噁心鬼的財產就全是我的了！我忍得多辛苦！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"물어내! 물어내라고, 이 괴물 계집애야!!","JPN":"弁償して！　責任取れよ！　この化け物！！","ENG":"It's all your fault! You cost me everything, you monster!!","TWN":"你賠給我！賠給我！！你這怪物丫頭！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"끼리끼리 노는군요.","JPN":"類は友を呼ぶのですね。","ENG":"Birds of a feather, huh.","TWN":"原來是在嬉鬧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왼쪽 뺨을 때리셔서 오른쪽 뺨을 갈겨 드렸습니다. 휴먼.","JPN":"左頬を殴ってきたので、右頬を殴り返しました、ヒューマン。","ENG":"Since you slapped my left cheek, I have returned in kind on your right cheek, human.","TWN":"你打我左臉，所以我打你右臉，人類。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어극……. 억……. 이빨……. 이빨이…….","JPN":"ゲッ……ガハ……歯……歯が……","ENG":"Ack… Ugh… My teeth… My teeth…","TWN":"噢嗚……嗚……我的牙齒……牙齒……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멘델슨의 피라미드 파워 클리닉에 가 보시죠. 임플란트도 상담해 줍니다.","JPN":"メンデルソンのピラミッド・パワークリニックに行ってみてください。\\nインプラントの相談も受け付けていますので。","ENG":"You should check out Mendelssohn's Pyramid Power Clinic. I hear they offer dental implants.","TWN":"你可以去曼德森金字塔能量診所，他們也有提供植牙服務。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……그러면 이제, 결백을 증명할 차례군요.","JPN":"……それではそろそろ、潔白を証明する番ですね。","ENG":"…Now, it's time to prove my innocence.","TWN":"……接下來，是證明清白的時候。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};